What does this program print?

```cpp
#include <iostream>
int main() {
    int x = 2;
    switch (x) {
        case 1: std::cout << "one\n";
        case 2: std::cout << "two\n";
        case 3: std::cout << "three\n";
        default: std::cout << "other\n";
    }
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
int main() {
    int month = 9;
    switch (month) {
        case 4: case 6: case 9: case 11:
            std::cout << "30 days\n";
            break;
        case 2:
            std::cout << "28 or 29 days\n";
            break;
        default:
            std::cout << "31 days\n";
            break;
    }
    return 0;
}
```

This program should print `Freezing` when temperature is 0 and `Boiling` when it is 100, otherwise `Normal`. What is wrong?

```cpp
#include <iostream>
int main() {
    int temp = 0;
    switch (temp) {
        case 0:
            std::cout << "Freezing\n";
        case 100:
            std::cout << "Boiling\n";
            break;
        default:
            std::cout << "Normal\n";
            break;
    }
    return 0;
}
```
